  const cols = grid[0].length;                                     // assignment(6) + binding(1) + binding(1) + constant(1)
  const countNeighbors = (r: number, c: number): number => {       // assignment(6) + binding(1) + binding(1) + binding(1)
    let count = 0;                                                  // assignment(6) + binding(1) + constant(1)
    for (let dr = -1; dr <= 1; dr++) {                             // loop(5) + assignment(6) + binding(1) + constant(1) + assignment(6)
