        if (dr === 0 && dc === 0) continue;                        // conditional(4) + binding(1) + constant(1) + binding(1) + constant(1)
        const nr = r + dr;                                          // assignment(6) + binding(1) + binding(1) + binding(1)
        const nc = c + dc;                                          // assignment(6) + binding(1) + binding(1) + binding(1)
        if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && grid[nr][nc]) count++; // conditional(4) + binding(1)*8 + constant(1)*2 + assignment(6)
      }
    }
    return count;                                                   // binding(1)
  };
  const result: boolean[][] = [];                                  // assignment(6) + binding(1)
